import {
  AppDefinition,
  AppReview,
  IntegrationPoint,
} from '../app-store.models';
import {
  AppDefinitionApiResponse,
  AppReviewApiResponse,
  AppStatusEnum,
  IntegrationPointApiResponse,
  ScreenIdEnum,
  WidgetSizeEnum,
} from './app-store-api.models';

/**
 * Maps API status enum to frontend string status
 */
function mapStatusFromApi(status: AppStatusEnum): AppDefinition['status'] {
  switch (status) {
    case AppStatusEnum.DRAFT:
      return 'DRAFT';
    case AppStatusEnum.PENDING_REVIEW:
      return 'PENDING_REVIEW';
    case AppStatusEnum.APPROVED:
      return 'APPROVED';
    case AppStatusEnum.REJECTED:
      return 'REJECTED';
    case AppStatusEnum.SUSPENDED:
      return 'SUSPENDED';
    default:
      return 'DRAFT';
  }
}

/**
 * Maps frontend status string to API enum
 */
export function mapStatusToApi(status: AppDefinition['status']): AppStatusEnum {
  switch (status) {
    case 'DRAFT':
      return AppStatusEnum.DRAFT;
    case 'PENDING_REVIEW':
      return AppStatusEnum.PENDING_REVIEW;
    case 'APPROVED':
      return AppStatusEnum.APPROVED;
    case 'REJECTED':
      return AppStatusEnum.REJECTED;
    case 'SUSPENDED':
      return AppStatusEnum.SUSPENDED;
    default:
      return AppStatusEnum.DRAFT;
  }
}

/**
 * Maps API screenId enum to frontend string
 */
function mapScreenIdFromApi(
  screenId: ScreenIdEnum,
): IntegrationPoint['screenId'] {
  switch (screenId) {
    case ScreenIdEnum.TRIP_DETAILS:
      return 'TRIP_DETAILS';
    case ScreenIdEnum.VEHICLE_ACTIVITY:
      return 'VEHICLE_ACTIVITY';
    case ScreenIdEnum.DASHBOARD:
      return 'DASHBOARD';
    case ScreenIdEnum.REPORTS:
      return 'REPORTS';
    default:
      return 'TRIP_DETAILS';
  }
}

/**
 * Maps frontend screenId string to API enum
 */
export function mapScreenIdToApi(
  screenId: IntegrationPoint['screenId'],
): ScreenIdEnum {
  switch (screenId) {
    case 'TRIP_DETAILS':
      return ScreenIdEnum.TRIP_DETAILS;
    case 'VEHICLE_ACTIVITY':
      return ScreenIdEnum.VEHICLE_ACTIVITY;
    case 'DASHBOARD':
      return ScreenIdEnum.DASHBOARD;
    case 'REPORTS':
      return ScreenIdEnum.REPORTS;
    default:
      return ScreenIdEnum.TRIP_DETAILS;
  }
}

/**
 * Maps API widgetSize enum to frontend string
 */
function mapWidgetSizeFromApi(
  widgetSize: WidgetSizeEnum,
): IntegrationPoint['widgetSize'] {
  switch (widgetSize) {
    case WidgetSizeEnum.MEDIUM:
      return 'MEDIUM';
    case WidgetSizeEnum.FULL_WIDTH:
      return 'FULL_WIDTH';
    case WidgetSizeEnum.CARD:
      return 'CARD';
    default:
      return 'MEDIUM';
  }
}

/**
 * Maps frontend widgetSize string to API enum
 */
export function mapWidgetSizeToApi(
  widgetSize: IntegrationPoint['widgetSize'],
): WidgetSizeEnum {
  switch (widgetSize) {
    case 'MEDIUM':
      return WidgetSizeEnum.MEDIUM;
    case 'FULL_WIDTH':
      return WidgetSizeEnum.FULL_WIDTH;
    case 'CARD':
      return WidgetSizeEnum.CARD;
    default:
      return WidgetSizeEnum.MEDIUM;
  }
}

/**
 * Maps IntegrationPoint API response to frontend model
 */
function mapIntegrationPointFromApi(
  apiPoint: IntegrationPointApiResponse,
): IntegrationPoint {
  return {
    screenId: mapScreenIdFromApi(apiPoint.screenId),
    widgetSize: mapWidgetSizeFromApi(apiPoint.widgetSize),
    requiredPermissions: apiPoint.requiredPermissions,
  };
}

/**
 * Maps AppDefinition API response to frontend model
 */
export function mapAppDefinitionFromApi(
  apiResponse: AppDefinitionApiResponse,
): AppDefinition {
  return {
    id: apiResponse.id,
    name: apiResponse.name,
    description: apiResponse.description,
    shortDescription: apiResponse.shortDescription,
    iconUrl: apiResponse.iconUrl,
    userId: apiResponse.developerId,
    developerName: apiResponse.developerName,
    status: mapStatusFromApi(apiResponse.status),
    integrationPoints: apiResponse.integrationPoints.map(
      mapIntegrationPointFromApi,
    ),
    endpoint: {
      baseUrl: apiResponse.endpoint.baseUrl,
      healthCheckUrl: apiResponse.endpoint.healthCheckUrl,
    },
    pricing: {
      model: 'FREE', // Not in API response, default to FREE
      price: 0,
      currency: 'ZAR',
      trialDays: 0,
    },
    categories: apiResponse.categories,
    tags: apiResponse.tags,
    averageRating: apiResponse.averageRating,
    reviewCount: apiResponse.reviewCount,
    installCount: apiResponse.installCount,
    updatedAt: apiResponse.updatedDate,
    createdAt: apiResponse.createdDate,
  };
}

/**
 * Maps AppReview API response to frontend model
 */
export function mapAppReviewFromApi(
  apiResponse: AppReviewApiResponse,
): AppReview {
  return {
    id: apiResponse.id,
    appId: apiResponse.appId,
    userId: apiResponse.userId,
    userName: apiResponse.userName,
    organizationName: apiResponse.organizationName,
    rating: apiResponse.rating,
    title: apiResponse.title,
    comment: apiResponse.comment,
    developerResponse: apiResponse.developerResponse,
    isVerifiedPurchase: apiResponse.isVerifiedPurchase,
    helpfulCount: apiResponse.helpfulCount,
    createdAt: apiResponse.createdDate,
  };
}
