import { Injectable, inject } from '@angular/core';
import { HttpClient, HttpParams } from '@angular/common/http';
import { Observable } from 'rxjs';
import { map } from 'rxjs/operators';
import { AppDefinition } from '../models/app-store.models';
import {
  AppDefinitionApiResponse,
  AppDefinitionListApiResponse,
  AppListQueryParams,
  CreateAppDefinitionRequest,
  UpdateAppDefinitionRequest,
} from '../models/api/app-store-api.models';
import {
  mapAppDefinitionFromApi,
  mapScreenIdToApi,
  mapStatusToApi,
  mapWidgetSizeToApi,
} from '../models/api/app-store-api.mappers';
import { ApiUrlService } from '../../../core/services/api-url.service';

@Injectable({
  providedIn: 'root',
})
export class AppStoreService {
  private readonly http = inject(HttpClient);
  private readonly apiUrlService = inject(ApiUrlService);
  private readonly baseUrl: string;

  constructor() {
    this.baseUrl = `${this.apiUrlService.getCurrentApiUrl()}/appstore`;
  }

  /**
   * Get all app definitions with optional filtering
   * @param params Query parameters for filtering and pagination
   */
  getApps(params?: AppListQueryParams): Observable<AppDefinition[]> {
    let httpParams = new HttpParams();

    if (params) {
      if (params.offset !== undefined) {
        httpParams = httpParams.set('offset', params.offset.toString());
      }
      if (params.limit !== undefined) {
        httpParams = httpParams.set('limit', params.limit.toString());
      }
      if (params.sort !== undefined) {
        httpParams = httpParams.set('sort', params.sort);
      }
      if (params.filter !== undefined) {
        httpParams = httpParams.set('filter', params.filter);
      }
      if (params.status !== undefined) {
        httpParams = httpParams.set('status', params.status);
      }
      if (params.developerId !== undefined) {
        httpParams = httpParams.set('developerId', params.developerId);
      }
    }

    return this.http
      .get<AppDefinitionListApiResponse>(`${this.baseUrl}/apps`, {
        params: httpParams,
      })
      .pipe(map((response) => response.items.map(mapAppDefinitionFromApi)));
  }

  /**
   * Get app definition by ID
   * @param id App ID
   * @param developerId Optional developer ID filter
   */
  getAppById(
    id: string,
    developerId?: string,
  ): Observable<AppDefinition | null> {
    let httpParams = new HttpParams();
    if (developerId !== undefined) {
      httpParams = httpParams.set('developerId', developerId);
    }

    return this.http
      .get<AppDefinitionApiResponse>(`${this.baseUrl}/apps/${id}`, {
        params: httpParams,
      })
      .pipe(map(mapAppDefinitionFromApi));
  }

  /**
   * Create a new app definition
   * @param app App definition data
   */
  createApp(app: Partial<AppDefinition>): Observable<AppDefinition> {
    const request: CreateAppDefinitionRequest = {
      developerName: app.developerName ?? '',
      name: app.name ?? '',
      description: app.description ?? '',
      shortDescription: app.shortDescription ?? '',
      iconUrl: app.iconUrl ?? '',
      integrationPoints:
        app.integrationPoints?.map((point) => ({
          screenId: mapScreenIdToApi(point.screenId),
          widgetSize: mapWidgetSizeToApi(point.widgetSize),
          requiredPermissions: point.requiredPermissions,
        })) ?? [],
      endpoint: {
        baseUrl: app.endpoint?.baseUrl ?? '',
        healthCheckUrl: app.endpoint?.healthCheckUrl,
      },
      categories: app.categories ?? [],
      tags: app.tags ?? [],
    };

    return this.http
      .post<AppDefinitionApiResponse>(`${this.baseUrl}/apps`, request)
      .pipe(map(mapAppDefinitionFromApi));
  }

  /**
   * Update an existing app definition
   * @param id App ID
   * @param changes Partial app definition with changes
   */
  updateApp(
    id: string,
    changes: Partial<AppDefinition>,
  ): Observable<AppDefinition> {
    const request: UpdateAppDefinitionRequest = {
      id,
      name: changes.name,
      description: changes.description,
      shortDescription: changes.shortDescription,
      iconUrl: changes.iconUrl,
      integrationPoints: changes.integrationPoints?.map((point) => ({
        screenId: mapScreenIdToApi(point.screenId),
        widgetSize: mapWidgetSizeToApi(point.widgetSize),
        requiredPermissions: point.requiredPermissions,
      })),
      endpoint: changes.endpoint
        ? {
            baseUrl: changes.endpoint.baseUrl,
            healthCheckUrl: changes.endpoint.healthCheckUrl,
          }
        : undefined,
      categories: changes.categories,
      tags: changes.tags,
      state: changes.status ? mapStatusToApi(changes.status) : undefined,
    };

    return this.http
      .patch<AppDefinitionApiResponse>(`${this.baseUrl}/apps/${id}`, request)
      .pipe(map(mapAppDefinitionFromApi));
  }

  /**
   * Submit an app for review (changes status to PENDING_REVIEW)
   * @param id App ID
   */
  submitForReview(id: string): Observable<AppDefinition> {
    return this.updateApp(id, { status: 'PENDING_REVIEW' });
  }

  /**
   * Approve an app (admin only - changes status to APPROVED)
   * @param id App ID
   */
  approveApp(id: string): Observable<AppDefinition> {
    return this.updateStatusOnly(id, 'APPROVED');
  }

  /**
   * Reject an app (admin only - changes status to REJECTED)
   * @param id App ID
   */
  rejectApp(id: string): Observable<AppDefinition> {
    return this.updateStatusOnly(id, 'REJECTED');
  }

  /**
   * Suspend an app (admin only - changes status to SUSPENDED)
   * @param id App ID
   */
  suspendApp(id: string): Observable<AppDefinition> {
    return this.updateStatusOnly(id, 'SUSPENDED');
  }

  /**
   * Update only the status field of an app
   * @param id App ID
   * @param status New status
   */
  private updateStatusOnly(
    id: string,
    status: AppDefinition['status'],
  ): Observable<AppDefinition> {
    const request: UpdateAppDefinitionRequest = {
      id,
      state: mapStatusToApi(status),
    };

    return this.http
      .patch<AppDefinitionApiResponse>(`${this.baseUrl}/apps/${id}`, request)
      .pipe(map(mapAppDefinitionFromApi));
  }
}
