/**
 * API Response and Request DTOs for App Store
 * Based on Postman collection endpoints
 */

// ==================== Enums ====================

export enum AppStatusEnum {
  DRAFT = 0,
  PENDING_REVIEW = 1,
  APPROVED = 2,
  REJECTED = 3,
  SUSPENDED = 4,
}

export enum ScreenIdEnum {
  TRIP_DETAILS = 0,
  VEHICLE_ACTIVITY = 1,
  DASHBOARD = 2,
  REPORTS = 3,
}

export enum WidgetSizeEnum {
  MEDIUM = 0,
  FULL_WIDTH = 1,
  CARD = 2,
}

// ==================== API Response Models ====================

export interface AppDefinitionApiResponse {
  id: string;
  developerId: string;
  developerName: string;
  name: string;
  description: string;
  shortDescription: string;
  iconUrl: string;
  status: AppStatusEnum;
  integrationPoints: IntegrationPointApiResponse[];
  endpoint: {
    baseUrl: string;
    healthCheckUrl?: string;
  };
  categories: string[];
  tags: string[];
  averageRating: number;
  reviewCount: number;
  installCount: number;
  createdDate: string;
  updatedDate: string;
}

export interface IntegrationPointApiResponse {
  screenId: ScreenIdEnum;
  widgetSize: WidgetSizeEnum;
  requiredPermissions: string[];
}

export interface AppDefinitionListApiResponse {
  count: number;
  offset: number;
  limit: number;
  items: AppDefinitionApiResponse[];
}

export interface AppReviewApiResponse {
  id: string;
  appId: string;
  userId: string;
  userName: string;
  organizationName: string;
  rating: number;
  title: string;
  comment: string;
  developerResponse?: string;
  isVerifiedPurchase: boolean;
  helpfulCount: number;
  createdDate: string;
  updatedDate: string;
}

export interface AppReviewListApiResponse {
  count: number;
  offset: number;
  limit: number;
  items: AppReviewApiResponse[];
}

export interface AppInstallationApiResponse {
  id: string;
  ownerId: string;
  appId: string;
  appName: string;
  isEnabled: boolean;
  configuration: Record<string, unknown>;
  createdDate: string;
  updatedDate: string;
}

export interface AppInstallationListApiResponse {
  count: number;
  offset: number;
  limit: number;
  items: AppInstallationApiResponse[];
}

// ==================== API Request Models ====================

export interface CreateAppDefinitionRequest {
  developerName: string;
  name: string;
  description: string;
  shortDescription: string;
  iconUrl: string;
  integrationPoints: IntegrationPointRequest[];
  endpoint: {
    baseUrl: string;
    healthCheckUrl?: string;
  };
  categories: string[];
  tags: string[];
}

export interface IntegrationPointRequest {
  screenId: ScreenIdEnum;
  widgetSize: WidgetSizeEnum;
  requiredPermissions: string[];
}

export interface UpdateAppDefinitionRequest {
  id: string;
  name?: string;
  description?: string;
  shortDescription?: string;
  iconUrl?: string;
  integrationPoints?: IntegrationPointRequest[];
  endpoint?: {
    baseUrl: string;
    healthCheckUrl?: string;
  };
  categories?: string[];
  tags?: string[];
  state?: AppStatusEnum;
}

export interface CreateAppReviewRequest {
  appId: string;
  ownerId: string;
  userName: string;
  organizationName: string;
  rating: number;
  title: string;
  comment: string;
}

export interface InstallAppRequest {
  appId: string;
  ownerId: string;
  configuration?: Record<string, unknown>;
}

export interface UpdateAppConfigurationRequest {
  id: string;
  ownerId: string;
  configuration: Record<string, unknown>;
}

// ==================== Query Parameters ====================

export interface AppListQueryParams {
  offset?: number;
  limit?: number;
  sort?: string;
  filter?: string;
  status?: string;
  developerId?: string;
}

export interface ReviewListQueryParams {
  owner?: string;
  offset?: number;
  limit?: number;
  sort?: string;
  filter?: string;
}

export interface InstallationListQueryParams {
  owner?: string;
  offset?: number;
  limit?: number;
  sort?: string;
  filter?: string;
}
